file.content:
/* ── Global ── */
QMainWindow, QDialog {
    background: #FAF8F4;
}

/* ── Typography ── */
QWidget {
    color: #1A1917;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

/* ── Buttons ── */
QPushButton {
    background: #FFFFFF;
    border: 1px solid #E0DBD5;
    border-radius: 8px; /* Rounded corners */
    padding: 6px 16px;
    font-weight: 500;
}
QPushButton:hover {
    background: #FDFBFA;
    border-color: #C96442;
}
QPushButton:pressed {
    background: #F5EDE8;
}
QPushButton:default {
    background: #C96442;
    color: #FFFFFF;
    border: none;
}
QPushButton:default:hover {
    background: #D87555;
}

/* ── Inputs ── */
QLineEdit, QTextEdit, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox {
    background: #FFFFFF;
    border: 1px solid #E0DBD5;
    border-radius: 6px;
    padding: 6px;
}
QLineEdit:focus, QComboBox:focus {
    border: 1px solid #C96442;
}

/* ── Menu Bar ── */
QMenuBar {
    background: #FAF8F4;
    color: #1A1917;
    border-bottom: 1px solid #E5E0DB;
    padding: 2px 4px;
}
QMenuBar::item {
    padding: 4px 10px;
    border-radius: 5px;
    background: transparent;
}
QMenuBar::item:selected { background: #EDE9E5; }
QMenuBar::item:pressed  { background: #C96442; color: #FFFFFF; }

/* ── Menus ── */
QMenu {
    background: #FFFFFF;
    border: 1px solid #E0DBD5;
    border-radius: 8px;
    padding: 4px;
}
QMenu::item {
    padding: 6px 28px 6px 12px;
    border-radius: 5px;
    color: #1A1917;
}
QMenu::item:selected  { background: #F5EDE8; color: #C96442; }
QMenu::item:disabled  { color: #B4AFA9; }
QMenu::separator      { height: 1px; background: #E5E0DB; margin: 4px 8px; }

/* ── Toolbars ── */
QToolBar {
    background: #F5F2EE;
    border: none;
    border-bottom: 1px solid #E5E0DB;
    padding: 3px 6px;
    spacing: 3px;
}
QToolButton {
    background: transparent;
    border: none;
    border-radius: 6px;
    padding: 4px 8px;
    color: #1A1917;
}
QToolButton:hover   { background: #EDE9E5; }
QToolButton:pressed { background: #DDD8D2; }
QToolButton:checked { background: #F5EDE8; color: #C96442; border: 1px solid #E8D5CC; }

/* ── Dock Widgets ── */
QDockWidget {
    border: 1px solid #E5E0DB;
    titlebar-close-icon: url(:/Icons/Close.png);
    titlebar-normal-icon: url(:/Icons/Float.png);
}
QDockWidget::title {
    background: #F5F2EE;
    padding: 6px;
    border-bottom: 1px solid #E5E0DB;
    font-weight: bold;
}

/* ── Scroll Bars ── */
QScrollBar:vertical {
    background: #F5F2EE;
    width: 10px;
    margin: 0px;
}
QScrollBar::handle:vertical {
    background: #D1CDC7;
    min-height: 20px;
    border-radius: 5px;
    margin: 2px;
}
QScrollBar::handle:vertical:hover {
    background: #C96442;
}
QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {
    height: 0px;
}

/* ── Tab Widgets ── */
QTabWidget::pane {
    border: 1px solid #E5E0DB;
