/* ── Global ── */
QMainWindow, QDialog {
    background: #F1F5F9;
}

/* ── Typography ── */
QWidget {
    color: #0F172A;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Inter", Roboto, Helvetica, Arial, sans-serif;
    font-size: 13px;
}

/* ── Buttons ── */
QPushButton {
    background: #FFFFFF;
    border: 1px solid #CBD5E1;
    border-radius: 6px;
    padding: 6px 16px;
    font-weight: 500;
    color: #0F172A;
}
QPushButton:hover {
    background: #F8FAFC;
    border-color: #0369A1;
    color: #0369A1;
}
QPushButton:pressed {
    background: #E0F2FE;
}
QPushButton:default {
    background: #0369A1;
    color: #FFFFFF;
    border: none;
}
QPushButton:default:hover {
    background: #0284C7;
}
QPushButton:default:pressed {
    background: #075985;
}
QPushButton:disabled {
    background: #F1F5F9;
    color: #94A3B8;
    border-color: #E2E8F0;
}

/* ── Inputs ── */
QLineEdit, QTextEdit, QPlainTextEdit, QSpinBox, QDoubleSpinBox {
    background: #FFFFFF;
    border: 1px solid #CBD5E1;
    border-radius: 5px;
    padding: 5px 8px;
    selection-background-color: #BAE6FD;
    selection-color: #0C4A6E;
}
QLineEdit:focus, QTextEdit:focus, QPlainTextEdit:focus,
QSpinBox:focus, QDoubleSpinBox:focus {
    border: 1.5px solid #0369A1;
    outline: none;
}
QLineEdit:disabled, QTextEdit:disabled {
    background: #F8FAFC;
    color: #94A3B8;
}

/* ── ComboBox ── */
QComboBox {
    background: #FFFFFF;
    border: 1px solid #CBD5E1;
    border-radius: 5px;
    padding: 5px 8px;
    min-width: 80px;
}
QComboBox:focus {
    border: 1.5px solid #0369A1;
}
QComboBox::drop-down {
    subcontrol-origin: padding;
    subcontrol-position: top right;
    width: 22px;
    border-left: 1px solid #E2E8F0;
}
QComboBox QAbstractItemView {
    background: #FFFFFF;
    border: 1px solid #CBD5E1;
    border-radius: 6px;
    selection-background-color: #E0F2FE;
    selection-color: #0369A1;
    padding: 4px;
}

/* ── Menu Bar ── */
QMenuBar {
    background: #FFFFFF;
    color: #0F172A;
    border-bottom: 1px solid #E2E8F0;
    padding: 2px 6px;
}
QMenuBar::item {
    padding: 5px 12px;
    border-radius: 5px;
    background: transparent;
    font-weight: 450;
}
QMenuBar::item:selected { background: #F1F5F9; }
QMenuBar::item:pressed  { background: #0369A1; color: #FFFFFF; }

/* ── Menus ── */
QMenu {
    background: #FFFFFF;
    border: 1px solid #E2E8F0;
    border-radius: 8px;
    padding: 4px;
}
QMenu::item {
    padding: 6px 32px 6px 14px;
    border-radius: 4px;
    color: #0F172A;
}
QMenu::item:selected  { background: #E0F2FE; color: #0369A1; }
QMenu::item:disabled  { color: #94A3B8; }
QMenu::separator      { height: 1px; background: #E2E8F0; margin: 4px 8px; }
QMenu::indicator      { width: 14px; height: 14px; margin-left: 4px; }

/* ── Toolbars ── */
QToolBar {
    background: #FFFFFF;
    border: none;
    border-bottom: 1px solid #E2E8F0;
    padding: 4px 8px;
    spacing: 4px;
}
QToolBar::separator {
    background: #E2E8F0;
    width: 1px;
    margin: 4px 4px;
}
QToolButton {
    background: transparent;
    border: none;
    border-radius: 5px;
    padding: 5px 8px;
    color: #334155;
}
QToolButton:hover   { background: #F1F5F9; color: #0F172A; }
QToolButton:pressed { background: #E2E8F0; }
QToolButton:checked { background: #E0F2FE; color: #0369A1; border: 1px solid #BAE6FD; }
QToolButton:disabled { color: #94A3B8; }

/* ── Dock Widgets ── */
QDockWidget {
    border: 1px solid #E2E8F0;
    color: #0F172A;
}
QDockWidget::title {
    background: #F8FAFC;
    padding: 7px 10px;
    border-bottom: 1px solid #E2E8F0;
    font-weight: 600;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #475569;
}
QDockWidget::close-button, QDockWidget::float-button {
    border: none;
    background: transparent;
    padding: 2px;
}
QDockWidget::close-button:hover, QDockWidget::float-button:hover {
    background: #E2E8F0;
    border-radius: 3px;
}

/* ── Scroll Bars ── */
QScrollBar:vertical {
    background: #F8FAFC;
    width: 8px;
    margin: 0px;
}
QScrollBar::handle:vertical {
    background: #CBD5E1;
    min-height: 24px;
    border-radius: 4px;
    margin: 2px;
}
QScrollBar::handle:vertical:hover { background: #0369A1; }
QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical { height: 0px; }

QScrollBar:horizontal {
    background: #F8FAFC;
    height: 8px;
    margin: 0px;
}
QScrollBar::handle:horizontal {
    background: #CBD5E1;
    min-width: 24px;
    border-radius: 4px;
    margin: 2px;
}
QScrollBar::handle:horizontal:hover { background: #0369A1; }
QScrollBar::add-line:horizontal, QScrollBar::sub-line:horizontal { width: 0px; }

/* ── Tab Widgets ── */
QTabWidget::pane {
    border: 1px solid #E2E8F0;
    top: -1px;
    background: #FFFFFF;
    border-radius: 6px;
}
QTabBar::tab {
    background: #F1F5F9;
    border: 1px solid #E2E8F0;
    border-bottom: none;
    border-top-left-radius: 6px;
    border-top-right-radius: 6px;
    padding: 7px 14px;
    margin-right: 2px;
    color: #475569;
    font-weight: 500;
}
QTabBar::tab:selected {
    background: #FFFFFF;
    color: #0369A1;
    border-bottom: 1px solid #FFFFFF;
    font-weight: 600;
}
QTabBar::tab:hover:!selected {
    background: #E2E8F0;
    color: #0F172A;
}

/* ── Group Boxes ── */
QGroupBox {
    border: 1px solid #E2E8F0;
    border-radius: 6px;
    margin-top: 20px;
    padding: 8px;
    font-weight: 600;
    color: #334155;
}
QGroupBox::title {
    subcontrol-origin: margin;
    left: 10px;
    padding: 0 6px;
    background: #F1F5F9;
    color: #475569;
    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

/* ── Trees and Lists ── */
QTreeView, QListView, QTableView {
    background: #FFFFFF;
    border: 1px solid #E2E8F0;
    border-radius: 6px;
    alternate-background-color: #F8FAFC;
    selection-background-color: #E0F2FE;
    selection-color: #0369A1;
    outline: none;
}
QTreeView::item, QListView::item {
    padding: 4px 4px;
    border-radius: 3px;
}
QTreeView::item:hover, QListView::item:hover {
    background: #F1F5F9;
}
QTreeView::item:selected, QListView::item:selected {
    background: #E0F2FE;
    color: #0369A1;
}
QHeaderView::section {
    background: #F8FAFC;
    border: none;
    border-right: 1px solid #E2E8F0;
    border-bottom: 1px solid #E2E8F0;
    padding: 6px 10px;
    font-weight: 600;
    color: #475569;
    font-size: 12px;
}

/* ── Sliders ── */
QSlider::groove:horizontal {
    height: 4px;
    background: #E2E8F0;
    border-radius: 2px;
}
QSlider::handle:horizontal {
    background: #0369A1;
    border: none;
    width: 16px;
    height: 16px;
    margin: -6px 0;
    border-radius: 8px;
}
QSlider::handle:horizontal:hover {
    background: #0284C7;
}
QSlider::sub-page:horizontal {
    background: #0369A1;
    border-radius: 2px;
}

/* ── Progress Bars ── */
QProgressBar {
    background: #E2E8F0;
    border: none;
    border-radius: 4px;
    height: 6px;
    text-align: center;
    color: transparent;
}
QProgressBar::chunk {
    background: #0369A1;
    border-radius: 4px;
}

/* ── Status Bar ── */
QStatusBar {
    background: #FFFFFF;
    border-top: 1px solid #E2E8F0;
    color: #64748B;
    font-size: 12px;
}
QStatusBar::item { border: none; }

/* ── Splitter ── */
QSplitter::handle {
    background: #E2E8F0;
}
QSplitter::handle:hover {
    background: #0369A1;
}
QSplitter::handle:horizontal { width: 4px; }
QSplitter::handle:vertical   { height: 4px; }

/* ── Checkboxes and Radio Buttons ── */
QCheckBox, QRadioButton {
    color: #0F172A;
    spacing: 8px;
}
QCheckBox::indicator, QRadioButton::indicator {
    width: 16px;
    height: 16px;
    border: 1.5px solid #CBD5E1;
    border-radius: 3px;
    background: #FFFFFF;
}
QCheckBox::indicator:checked, QRadioButton::indicator:checked {
    background: #0369A1;
    border-color: #0369A1;
}
QCheckBox::indicator:hover, QRadioButton::indicator:hover {
    border-color: #0369A1;
}
QRadioButton::indicator { border-radius: 8px; }

/* ── Tooltips ── */
QToolTip {
    background: #0F172A;
    color: #F8FAFC;
    border: none;
    border-radius: 5px;
    padding: 5px 8px;
    font-size: 12px;
}

/* ── Frame/Panel backgrounds ── */
QFrame {
    border: none;
}
QFrame[frameShape="4"], QFrame[frameShape="5"] {
    color: #E2E8F0;
}

