void qSlicerMainWindowPrivate::init()
{
  Q_Q(qSlicerMainWindow);
  this->setupUi(q);

  this->setupStatusBar();
  q->setupMenuActions();
  this->StartupState = q->saveState();
  q->restoreGUIState();

  // Hot-reload stylesheet in dev mode.
  // Set SLICER_DEV_STYLESHEET=/path/to/your.qss before launching Slicer.
  // Any save to that file instantly re-applies the stylesheet — no restart needed.
  QString devQss = qEnvironmentVariable("SLICER_DEV_STYLESHEET");
  if (!devQss.isEmpty() && QFile::exists(devQss))
  {
