  Q_Q(qSlicerMainWindow);
  this->setupUi(q);

  this->setupStatusBar();
  q->setupMenuActions();
  this->StartupState = q->saveState();
  q->restoreGUIState();

  // Hot-reload stylesheet in dev mode.
  // Set SLICER_DEV_STYLESHEET=/path/to/your.qss before launching Slicer.
  // Any save to that file instantly re-applies the stylesheet — no restart needed.
  QString devQss = qEnvironmentVariable("SLICER_DEV_STYLESHEET");
  if (!devQss.isEmpty() && QFile::exists(devQss))
  {
    auto applyQss = [devQss]() {
      QFile f(devQss);
      if (f.open(QIODevice::ReadOnly | QIODevice::Text))
      {
        qApp->setStyleSheet(QString::fromUtf8(f.readAll()));
        qDebug() << "[hot-reload] stylesheet applied:" << devQss;
      }
    };
    applyQss();
    auto* watcher = new QFileSystemWatcher(q);
    watcher->addPath(devQss);
    // Some editors write by replace (remove+create); re-add path after each change.
    QObject::connect(watcher, &QFileSystemWatcher::fileChanged, q,
      [watcher, devQss, applyQss](const QString& path) {
        applyQss();
        if (!watcher->files().contains(path))
          watcher->addPath(path); // re-add if editor did atomic replace
      });
  }
}

